var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이상하네요. 지원 부대가 도착할 시간은 한참 지났어요.","JPN":"おかしいですね。応援部隊の予定到着時間からかなり過ぎてしまいました。","ENG":"That's strange. The reinforcements should have arrived a long time ago.","TWN":"奇怪，支援部隊怎麼還沒到。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"침식파가 너무 강하면 통신이 끊길 때도 있잖아.","JPN":"侵食波が強すぎるとたまに通信が切れる時もあるでしょ。","ENG":"Sometimes the Corruption ray can jam the comms.","TWN":"侵蝕波很強的時候會造成通信故障。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지원 부대까지 연락이 가지 못한 거 아냐?","JPN":"応援部隊に連絡が届いてないんじゃない？","ENG":"Maybe they didn't get the message?","TWN":"是不是沒聯繫到支援部隊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"과연. 그런 상황도 배제할 수 없겠네요.","JPN":"なるほど。そのような状況も否定できませんね。","ENG":"True. I suppose that's possible.","TWN":"也許吧，也不能排除那種情況。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유미나 양은 현역 태스크포스라 그런지 상황 판단이 뛰어나군요. 훌륭해요.","JPN":"ミナさんは現役タスクフォースですので、状況判断能力に優れていますね。素晴らしいです。","ENG":"Perhaps because of your status as an active TASKFORCE member, you demonstrate excellent situational awareness. Outstanding.","TWN":"劉米娜小姐不愧是特遣勢力現役，判讀能力很出色啊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아니. 추켜세워 줄 만큼 대단하진 않아.","JPN":"い、いや。そんなに褒められるほどではないよ。","ENG":"Eh, not really. I'm not that impressive.","TWN":"啊，沒有啦，我也沒有你說的那麼出色。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"앗, CCTV를 복구했어~","JPN":"よし、防犯カメラの記録を復旧できたよぉ！","ENG":"Oh, the security camera's back online.","TWN":"哎，我修復監控錄影了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으음~ 이 애들이 자율 방어 시스템을 망가트린 범인들 같아~","JPN":"う～ん、この子たちが自律防御システムを壊した犯人みたいだねぇ。","ENG":"Hmm... I think these kids must be the culprits behind the ADS!","TWN":"好像這些孩子就是破壞自主防禦系統的犯人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"어? 저 사람들은......?","JPN":"あれ？　あの人たちは……？","ENG":"Huh? Aren't they...","TWN":"額？他們是……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘이랑 걔가 데리고 다니는 아이언 스틸 소대원들이에요!","JPN":"ナイエルと、あの子といつも一緒にいるアイアンスチールの小隊員です！","ENG":"It's Naielle and her Iron Steel squad members!","TWN":"是奈爾和她帶領的鋼鐵小隊成員！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘? 칼을 세 자루나 차고 다니는 그 애 말이야?","JPN":"ナイエル？　剣を3本も持ち歩いているあの子？","ENG":"Naielle? You mean the girl who goes around with three swords?","TWN":"奈爾？是帶三把刀的那個孩子嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"한 번에 쥐지도 못할 텐데 왜 세 자루나 들고 다닌담. 무겁기만 하게...... 흐아암......","JPN":"一気に構えることもできないくせに、何で3本も持っているのか不思議だったんだよぉ。重いだけよね……ふあぁん……","ENG":"Why does she bother carrying three? You can only hold two at once... It'll only weigh her down. *Yawn*...","TWN":"那三把刀也沒法同時拿在手上，她幹嘛隨身攜帶啊，怪沉的……（打哈欠）……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어릴 때 본 만화에서 좋아하는 인물이 저런 무기를 썼다고 하더군요.","JPN":"子どもの頃に好きだった漫画のキャラクターがあのような武器を持っていたらしいですね。","ENG":"Apparently one of her favorite manga characters uses three swords.","TWN":"聽說是小時候看到的漫畫人物使用那種武器。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 지금 중요한 사실은 나이엘의 취향이 아니에요. ","JPN":"しかし今大事なのはナイエルさんの好みではありません。","ENG":"But Naielle's preference for weaponry is the least of our concerns right now. ","TWN":"但現在重要的不是奈爾喜歡什麼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"영상을 보아, 자율 방어 시스템이 망가진 틈을 타서 훈련 장소를 무단 이탈한 모양이네요.","JPN":"映像からして、自律防御システムが壊れた隙をついて訓練場所から無断で離脱したようです。","ENG":"The video suggests they left the training area while the ADS was down.","TWN":"看影片中的樣子，他們應該是趁著自主防禦系統癱瘓時脫離了訓練場所。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 결투 운운할 때부터 어째 골치 아픈 녀석 같더니......","JPN":"そうなの？　決闘云々言い出した時からなんとなく厄介者のにおいがすると思ったら……","ENG":"Really? I knew she'd be a pain in the butt when she asked for a duel...","TWN":"是嗎？當他出要決鬥什麼的時候，我就知道一定是個令人頭疼的傢伙……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유미나 학생, 미안하지만 한 가지 부탁을 더 해도 될까요?","JPN":"ヤナギ・ミナさん。申し訳ございませんが、もう一つお願いしたいことがあります。","ENG":"May I ask you another favor, Mina?","TWN":"劉米娜同學，不好意思，我能再拜託你一件事嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 무슨 부탁?","JPN":"うん？　何？","ENG":"Huh? What favor?","TWN":"嗯？什麼事？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 학생의 실력은 분명 아카데미에서 우수한 축에 속해요.","JPN":"ナイエルさんの実力は確かにアカデミーの中でも優秀です。","ENG":"There is no doubt Naielle is one of the more capable students at the Academy.","TWN":"奈爾同學的實力在學院的學生中是屬於很優秀的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 이면세계에는 그녀가 감당할 수 없는 위험이 산재해 있습니다.","JPN":"しかしこの裏世界には、彼女の手に負えない危険も散在しています。","ENG":"But the Counterside is rife with threats even she cannot handle.","TWN":"但她無法抵禦異界中的危險情況。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러니 나쁜 일이 생기기 전에 그녀를 데리고 와 주시겠어요?","JPN":"ですので、よからぬことが起きる前に彼女を連れ戻してくれませんか？","ENG":"So could you please bring her back before anything terrible happens?","TWN":"所以趁還沒發生糟糕的事之前，你能把她帶回來嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"마음 같아선 함께 가고 싶지만, 당장은 학생들을 지킬 사람도 부족한 상황이에요.","JPN":"ご一緒したい気持ちは山々ですが、生徒たちを守る人員も足りない状況です。","ENG":"I'd go with you, but we're already stretched pretty thin here as it is.","TWN":"我雖然也想去，但現在的情況是保護學生安全的人手已經不足了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금 이 일을 맡길 수 있는 사람은 미나 학생뿐입니다.","JPN":"現状これを頼める人はミナさんしかいません。","ENG":"You're the only person I can count on right now.","TWN":"我現在能拜託的人只剩下米娜同學了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"확실히 이런 건 학교가 회사랑 다르긴 하네......","JPN":"なるほど、こういうところが学校と会社の違いか……","ENG":"I guess that's the difference between a school and a company...","TWN":"果然學校和公司還是不同的……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소대장이나 선배였으면 자기가 벌인 일은 자기가 책임지라고 했을 텐데.","JPN":"小隊長か先輩だったら、自分がやらかしたことは自分で責任負えって言うはずなのに。","ENG":"The Commander or Shiyoon would have held her responsible for her own actions.","TWN":"如果是小隊長或者前輩遇到了這樣的事，一定會說自己的爛攤子自己收拾。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......아니, 생각해 보면 역시 이쪽이 당연한 거겠지.","JPN":"……いや、よく考えたらやっぱりこれが普通だよね。","ENG":"Then again... I think this might be the right thing to do.","TWN":"……算了，這樣才是正常的嘛。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양?","JPN":"ミナさん？","ENG":"Mina?","TWN":"米娜？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 다녀 올게.","JPN":"いいよ。行ってくる。","ENG":"Fine. I'll go get her.","TWN":"好吧，我去。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대신 상황에 따라서 비용이 조금 발생할 수도 있어. 그건 학생회장님이 책임져 주기다?","JPN":"でも状況によって費用が発生するかもしれないよ。それは生徒会長が保証してくれるんだね？","ENG":"But it might cost you, depending on what happens. Can I count on you to take care of that?","TWN":"但要提前說好，根據具體情況有可能會產生一些費用。這個學生會長會負責的吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼요. 자원 봉사를 요구할 생각은 없어요. 학생의 생명이 최우선입니다.","JPN":"もちろんです。ボランティアで強要するつもりはありません。生徒の命が最優先です。","ENG":"Of course. I wouldn't ask you to do something so dangerous without due compensation. The students' lives come first.","TWN":"當然啦。我可不會要求你志願服務。學生的生命是第一位的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시원시원해서 좋네.","JPN":"話が早くていいね。","ENG":"I like your style.","TWN":"性格果然爽快。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 다들, 갈까?","JPN":"さてと、行こうか！","ENG":"Alright, are you two ready?","TWN":"那麼，我們出發吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에엑? 우리도 가는 거야?","JPN":"ええ？　私たちも行くの？","ENG":"Huh? We're coming too?","TWN":"啊？我們也去嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당연하지. 살아도 한 몸, 죽어도 한 몸이라며.","JPN":"当たり前でしょ。同じ船に乗った仲間だから死ぬ時も一緒！　って言ったよね。","ENG":"Of course. What happened to \\"we live as one, die as one?\\"","TWN":"當然啦，不是你說我們要死要活都是一體嘛。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 말이 그렇다는 거지......","JPN":"いや、それはその時のノリで……","ENG":"That was just a figure of speech...","TWN":"我只是說說而已……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 그 녀석, 나 혼자 가서는 자존심 때문에라도 안 오려고 할 걸.","JPN":"それにあいつのことだから、私が一人で迎えに行ってもプライドで意地を張ってついてこないと思う。","ENG":"Besides, if I go by myself, she won't come along because of her pride.","TWN":"還有就算我找到那個傢伙，她也會因為自尊心不會同意跟我回來的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일이 복잡해지는 것보다는 낫잖아.","JPN":"これ以上複雑な状況を作りたくないでしょ。","ENG":"We wouldn't want to complicate things, do we?","TWN":"到時候事情就麻煩了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"우으...... 아, 알았어.","JPN":"うぅ……わ、わかった。","ENG":"Aw... F-fine.","TWN":"嗚……知、知道了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"대신 선배가 절 꼭 지켜줘야 해요!","JPN":"でも、先輩がしっかり守ってくださいね！","ENG":"But you'd better keep me safe, Ray!","TWN":"那前輩一定要好好保護我！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선배! 듣고 있어요?!","JPN":"先輩！　聞いてます！？","ENG":"Ray! Did you hear what I said?","TWN":"前輩！你聽到了嗎？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"어?","JPN":"うん？","ENG":"Huh?","TWN":"啊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"아, 응. 미안. 듣고 있었어.","JPN":"あ、うん。ごめん。聞いてたよ。","ENG":"Oh, right. Sorry. I heard you.","TWN":"哦，抱歉。我在聽呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어휴, 무슨 생각을 하느라 그렇게 멍하니 있어요.","JPN":"もぉ、何でそんなぼーっとするんですか？","ENG":"Geez, why are you spacing out in a moment like this?","TWN":"哎呦，你想什麼呢，在那發什麼呆。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이럴 때일수록 정신 바짝 차려야 한다고요!","JPN":"こんな時こそ、気をしっかり引き締めておかないと！","ENG":"You have to stay focused especially when things get hectic like now!","TWN":"越是這種時候，越要打起精神嘛！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그래. 자신은 없지만...... 노력해 볼게.","JPN":"う、うん。自信はないけど……努力してみる。","ENG":"R-right. Although I'm not so confident... I'll try my best.","TWN":"好、好吧。雖然沒什麼信心……但我會努力的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};